msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = {
  ok: true,
  accepted: true
};
return msg;

const base = (env.get("PHAB_API_BASE") || "http://localhost:3000/api").replace(/\/+$/, "");
const token = env.get("SUPPORT_INTEGRATION_TOKEN") || "";

const envelope = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};
const raw = (
  envelope.payload &&
  typeof envelope.payload === "object" &&
  envelope.phone === undefined &&
  envelope.content === undefined
)
  ? envelope.payload
  : envelope;

function normalizeEmpty(value) {
  const text = String(value ?? "").trim();
  if (!text) {
    return undefined;
  }

  const lowered = text.toLowerCase();
  if (lowered === "null" || lowered === "undefined") {
    return undefined;
  }

  return text;
}

const phone = normalizeEmpty(raw.phone);
const emailRaw = normalizeEmpty(raw.email);
const email = emailRaw ? emailRaw.toLowerCase() : undefined;
const content = normalizeEmpty(raw.content);
const notificationType = normalizeEmpty(raw.notificationType) || "VIVA";
const externalUserId = normalizeEmpty(raw.externalUserId);
const externalChatId = normalizeEmpty(raw.externalChatId);

if (!phone && !email && !externalUserId && !externalChatId) {
  node.warn("Viva payload without identifiers");
  return [null, null];
}

const tgMsg = {
  method: "POST",
  url: "http://80.78.255.203:2606/api/viva_msg",
  headers: {
    "Content-Type": "application/json"
  },
  payload: raw
};

const supportHeaders = {
  "Content-Type": "application/json"
};

if (token) {
  supportHeaders["x-integration-token"] = token;
}

const supportMsg = {
  method: "POST",
  url: `${base}/support/dialogs/events`,
  headers: supportHeaders,
  payload: {
    connector: "MAX_BOT",
    phone,
    email,
    externalUserId,
    externalChatId,
    displayName: "Viva CRM",
    direction: "SYSTEM",
    kind: "SYSTEM",
    deliverToClient: true,
    text: content
      ? `Служебное сообщение Viva CRM (${notificationType}): ${content}`
      : `Служебное сообщение Viva CRM (${notificationType})`,
    meta: {
      source: "viva_crm",
      notificationType,
      receivedAt: new Date().toISOString(),
      vivaPayload: raw
    }
  }
};

return [tgMsg, supportMsg];

const code = Number(msg.statusCode || 0);

if (code < 200 || code >= 300) {
  node.warn(`TG endpoint failed: HTTP ${code || "n/a"}; body=${typeof msg.payload === "string" ? msg.payload : JSON.stringify(msg.payload)}`);
} else {
  node.log(`TG endpoint OK: HTTP ${code}`);
}

return msg;

const code = Number(msg.statusCode || 0);

if (code < 200 || code >= 300) {
  node.warn(`Support ingest failed: HTTP ${code || "n/a"}; body=${typeof msg.payload === "string" ? msg.payload : JSON.stringify(msg.payload)}`);
} else {
  node.log(`Support ingest OK: HTTP ${code}`);
}

return msg;

const error = msg.error || {};
node.error(String(error.message || "Unhandled Viva flow error"), msg);
return msg;
